se balaye,—"janilana sakala karana',NULL,NULL),('cb.antya.5.586','cb','cb.antya.5','ЧБ Антья 5.586',586,NULL,'yata bada bada loka cari-dik haite
sabei aisena avadhutera dekhite',NULL,NULL),('cb.antya.5.587','cb','cb.antya.5','ЧБ Антья 5.587',587,NULL,'kоnа dik haite kona rajara laskara
asiyache, tara padatika bahutara',NULL,NULL),('cb.antya.5.588','cb','cb.antya.5','ЧБ Антья 5.588',588,NULL,'ataeva padatika sakala bhavaka ei se karane ''hari hari'' kare japa',NULL,NULL),('cb.antya.5.589','cb','cb.antya.5','ЧБ Антья 5.589',589,NULL,'eba nahe, kona padatika ani thake tabe kata dina edaiba ei pake',NULL,NULL),('cb.antya.5.590','cb','cb.antya.5','ЧБ Антья 5.590',590,NULL,'ataeva cala sabe aji ghare yai cupe cape dina dasa vasi'' thaki bhai"',NULL,NULL),('cb.antya.5.591','cb','cb.antya.5','ЧБ Антья 5.591',591,NULL,'eta bali'' dasyu-gana gela nija-ghare avadhuta-candra prabhu svacchande vihare',NULL,NULL),('cb.antya.5.592','cb','cb.antya.5','ЧБ Антья 5.592',592,NULL,'nityananda-carana bhajaye ye ye jane sarva-vighna khande taha sabara smarane',NULL,NULL),('cb.antya.5.593','cb','cb.antya.5','ЧБ Антья 5.593',593,NULL,'hena nityananda prabhu vihare apane
tahane karite vighna pare kon jane',NULL,NULL),('cb.antya.5.594','cb','cb.antya.5','ЧБ Антья 5.594',594,NULL,'avidya khandaye yanra dasera smarane
se prabhure vighna karibeka kon jane
sarva-gana-saha vighna-natha yanra dasa yanra amsa rudra kare jagata-vinasa
yanra amsa nadite bhuvana kampa haya hena prabhu nityananda, kare tana bhaya
yasyamsamsamsa-bhagena visvotpatti-layodayah bhavanti kila visvatmams tam tvadyaham gatim gata
mad-bhayad vati vato ''yam suryas tapati mad-bhayat
varsatindro dahaty agnir mrtyus carati mad-bhayat
yo ''ntah pravisya bhutani bhutair atty akhilasrayah sa visnv-akhyo ''dhiyajno ''sau kalah kalayatam prabhuh
na casya kascid dayito na dvesyo na ca bandhavah
avisaty apramatto ''sau pramattam janam anta-krt
yad-bhayad vati vato ''yam suryas tapati yad-bhayat yad-bhayad varsate devo bha-gano bhati yad-bhayat
yad vanaspatayo bhita latas causadhibhih saha
sve sve kale ''bhigrhnanti puspani ca phalani ca
sravanti sarito bhita notsarpaty udadhir yatah agnir indhe sa-giribhir bhur na majjati yad-bhayat
nabho dadati svasatam padam yan-niyamad adah
lokam sva-deham tanute mahan saptabhir avrtam
gunabhimanino devah sargadisv asya yad-bhayat
vartante ''nuyugam yesam vasa etac caracaram
so ''nanto ''nta-karah kalo ''nadir adi-krd avyayah janam janena janayan marayan mrtyunantakam
yat-pada-pallava-yugam vinidhaya kumbha- dvandve pranama-samaye sa ganadhirajah
vighnan vihantum alam asya jagat-trayasya
govindam adi-purusam tam aham bhajami',NULL,NULL),('cb.antya.5.597','cb','cb.antya.5','ЧБ Антья 5.597',597,NULL,'sarva navadvipe kare svacchande kirtana svacchande karena krida bhojana sayana',NULL,NULL),('cb.antya.5.598','cb','cb.antya.5','ЧБ Антья 5.598',598,NULL,'sarva-ange sakala amulya alankara yena dekhi baladeva—rohini-kumara
katpura, tambula prabhu karena carvana isat hasiya mohe jaga-jana-mana',NULL,NULL),('cb.antya.5.600','cb','cb.antya.5','ЧБ Антья 5.600',600,NULL,'abhaya-paramananda bule sarva-sthane abhaya-paramananda bhakta-gosthi-sane',NULL,NULL);
INSERT OR REPLACE INTO verse_texts (id,verse_id,edition_id,translation,purport) VALUES ('cb.antya.5.476.ru','cb.antya.5.476','cb-ru','Через некоторое время оба Прабху успокоились и сели рядом.',NULL),('cb.antya.5.477.ru','cb.antya.5.477','cb-ru','Мудрый Адвайта сложил молитвенно руки и с радостью предложил Нитьянанде Своё почтение.',NULL),('cb.antya.5.478.ru','cb.antya.5.478','cb-ru','"Нитьянанда – это Твоя форма, и имя Твоё – Нитьянанда. Ты олицетворение трансцендентных качеств Господа Чайтаньи".',NULL),('cb.antya.5.479.ru','cb.antya.5.479','cb-ru','"Ты высшая причина освобождения всех живых существ. Ты хранишь религиозные принципы даже во время полного уничтожения".',NULL),('cb.antya.5.480.ru','cb.antya.5.480','cb-ru','"Ты распространяешь преданное служение Господу Чайтанье в настроении экстатической любви. Ты ветвь дерева Господа Чайтаньи, имеющая все полномочия".',NULL),('cb.antya.5.481.ru','cb.antya.5.481','cb-ru','"Ты Верховный Наставник всех преданных, во главе с Брахмой, Шивой и Нарадой".',NULL),('cb.antya.5.482.ru','cb.antya.5.482','cb-ru','"По Твоей милости каждый может обрести преданное служение Вишну, но Ты никогда не гордишься этим".
Стих 483-484
"Ты освободитель падших душ. Ты не ищешь недостатков в других. Только очень добродетельный человек может Тебя понять. Ты олицетворение всех жертвоприношений. Просто вспоминая о Тебе, люди освобождаются от оков невежества".
Прославляя Шри Нитьянанду Прабху, Шри Адвайта Прабху сказал: "Ты освободитель падших душ и Ты не ищешь недостатки в падших. Никто, кроме самых благочестивых людей не могут понять Тебя. Ты олицетворение всех жертвоприношений. Просто вспоминая о Тебе, люди рвут все оковы невежества".',NULL),('cb.antya.5.485.ru','cb.antya.5.485','cb-ru','"Если Ты Сам не раскроешь Себя, то кто сможет Тебя узнать?"',NULL),('cb.antya.5.486.ru','cb.antya.5.486','cb-ru','"Ты свободен от гнева, Ты высшее счастье и Ты управляешь всем. Ты тысячеглавый изначальный Господь, поддерживающий все вселенные".',NULL),('cb.antya.5.487.ru','cb.antya.5.487','cb-ru','"Ты Лакшмана, разрушитель династий демонов. Ты Халадхара, сын пастуха".',NULL),('cb.antya.5.488.ru','cb.antya.5.488','cb-ru','"Ты воплотился в этом мире, чтобы освободить глупцов, падших и страдающих".',NULL),('cb.antya.5.489.ru','cb.antya.5.489','cb-ru','"Преданное служение, о котором грезят лучшие из йогов-мистиков и мудрецов, по Твоей милости может получить каждый".',NULL),('cb.antya.5.490.ru','cb.antya.5.490','cb-ru','Пока Адвайта прославлял Нитьянанду, Он погрузился в экстатические переживания и совершенно забыл о Себе.',NULL),('cb.antya.5.491.ru','cb.antya.5.491','cb-ru','Адвайта и некоторые наиболее удачливые души знают величие славы Нитьянанды.',NULL),('cb.antya.5.492.ru','cb.antya.5.492','cb-ru','В мнимых ссорах, возникающих между Ними нет ничего, кроме источника трансцендентного счастья, если человек понимает их суть.',NULL),('cb.antya.5.493.ru','cb.antya.5.493','cb-ru','Кому дана власть понять слова Адвайты, который неотличен от Верховного Господа, и в этом нет сомнений.
Смотрите стих адваитам харинадвайтад из записной книжки Шри Сварупы Дамодары, процитированный в комментарии к главе 9, тексту 86
этой книги.',NULL),('cb.antya.5.494.ru','cb.antya.5.494','cb-ru','Таким образом, двое Прабху радостно принялись обсуждать благоприятные темы, связанные с Господом Кришной.',NULL),('cb.antya.5.495.ru','cb.antya.5.495','cb-ru','Нитьянанда с Адвайтой обменивались сокровенными мыслями и наслаждались беспредельным счастьем.',NULL),('cb.antya.5.496.ru','cb.antya.5.496','cb-ru','После встречи, Нитьянанда попросил у Адвайты разрешение отправиться в Навадвипу.',NULL),('cb.antya.5.497.ru','cb.antya.5.497','cb-ru','Первым делом, Он навестил матушку Шачи и предложил поклоны её стопам.',NULL),('cb.antya.5.498.ru','cb.antya.5.498','cb-ru','Когда Шачимата увидела Нитьянанду Сварупу, её материнскому счастью не было границ.',NULL),('cb.antya.5.499.ru','cb.antya.5.499','cb-ru','Матушка Шачи сказала: "Мой дорогой сын, Ты конечно же Сверхдуша, потому что я только что захотела Тебя увидеть".',NULL),('cb.antya.5.500.ru','cb.antya.5.500','cb-ru','"Зная о моём желании, Ты так быстро появился здесь. Кто в этом мире способен понять Тебя?"',NULL),('cb.antya.5.501.ru','cb.antya.5.501','cb-ru','"Мой дорогой сын, оставайся здесь, в Навадвипе на какое-то время, чтобы я могла видеть Тебя хоть раз в десять, пятнадцать или тридцать дней".
Фраза даше пакше масе означает "после десяти дней, после пятнадцати дней, или через месяц".',NULL),('cb.antya.5.502.ru','cb.antya.5.502','cb-ru','"Я страдала и желала видеть Тебя. Теперь по воле провидения Ты пришёл, чтобы избавить меня от боли разлуки".',NULL),('cb.antya.5.503.ru','cb.antya.5.503','cb-ru','Услышав слова Шачиматы, Нитьянанда улыбнулся, потому что знал всё о её славе, от начала и до конца.',NULL),('cb.antya.5.504.ru','cb.antya.5.504','cb-ru','Нитьянанда сказал: "Послушай, матушка Шачи – ты мать всех! Я пришёл сюда, чтобы тебя увидеть".',NULL),('cb.antya.5.505.ru','cb.antya.5.505','cb-ru','"Я испытываю огромное желание видеть тебя здесь, и по твоей просьбе, Я остаюсь в Навадвипе".',NULL),('cb.antya.5.506.ru','cb.antya.5.506','cb-ru','После разговора с Шачиматой, Нитьянанда счастливо гулял по всей Навадвипе.',NULL),('cb.antya.5.507.ru','cb.antya.5.507','cb-ru','Нитьянанда со Своими спутниками наслаждался играми в киртан в каждом доме Навадвипы.',NULL),('cb.antya.5.508.ru','cb.antya.5.508','cb-ru','После появления Нитьянанды Прабху, Навадвипа стала олицетворением восторженного киртана.',NULL),('cb.antya.5.509.ru','cb.antya.5.509','cb-ru','Он постоянно вместе со своими преданными проводил санкиртаны, не пропуская ни одного дома.',NULL),('cb.antya.5.510.ru','cb.antya.5.510','cb-ru','Просто глядя на изумительные одежды возглавляющего группу санкиртаны Нитьянанды, благочестивые люди испытывали огромное удовольствие.
Благочестивым людям было особенно приятно видеть энтузиазм Шри Нитьянанды Прабху, проводящего санкиртану.',NULL),('cb.antya.5.511.ru','cb.antya.5.511','cb-ru','На Его голове был тюрбан из разноцветного тонкого шёлка, украшенный венками из цветов.',NULL),('cb.antya.5.512.ru','cb.antya.5.512','cb-ru','На Его шее красовались разные ожерелья из драгоценных камней, жемчуга и золота, а Его уши были украшены золотыми серьгами с жемчужинами.',NULL),('cb.antya.5.513.ru','cb.antya.5.513','cb-ru','Он носил красивые золотые нарукавники и браслеты. Я затрудняюсь сказать, сколько цветочных гирлянд было на Его теле.',NULL),('cb.antya.5.514.ru','cb.antya.5.514','cb-ru','Все Его тело было умащено пастой из сандала и горочаны. Он всегда был весел, как мальчик-пастушок.',NULL),('cb.antya.5.515.ru','cb.antya.5.515','cb-ru','Он без усилий удерживал изумительный железный посох, а все Его пальцы были украшены золотыми кольцами.',NULL),('cb.antya.5.516.ru','cb.antya.5.516','cb-ru','Его одежда из тончайшего белого, синего и желтого шёлка, приводила всех в полный восторг.',NULL),('cb.antya.5.517.ru','cb.antya.5.517','cb-ru','За поясом Он носил хлыст, флейту и бамбуковую палку. Один Его вид и память о Нём, завораживали умы всех людей в мире.',NULL),('cb.antya.5.518.ru','cb.antya.5.518','cb-ru','Его лотосные щиколотки были украшены серебряными браслетами и колокольчиками, которые издавали мелодичный звон, когда Он шёл поступью царя слонов.',NULL),('cb.antya.5.519.ru','cb.antya.5.519','cb-ru','Там, куда бросал Свой взгляд Нитьянанда, всё наполнялось вкусами любви к Кришне.',NULL),('cb.antya.5.520.ru','cb.antya.5.520','cb-ru','Таким образом, совершенно счастливый Нитьянанда жил в Навадвипе – месте рождения Господа Чайтаньи.
Навадвипа – место рождения Шри Чайтаньядевы. Эта часть Навадвипы известна как Шридхама Майапура.',NULL),('cb.antya.5.521.ru','cb.antya.5.521','cb-ru','К тому же, Навадвипа является столицей Матхуры. Никто не знает, сколько там проживало людей.',NULL),('cb.antya.5.522.ru','cb.antya.5.522','cb-ru','Там было такое огромное количество благочестивых жителей, что один их вид избавлял грешников от всех последствий их неблаговидных поступков.',NULL),('cb.antya.5.523.ru','cb.antya.5.523','cb-ru','Среди благочестивых людей, конечно же жили и грешники. Даже коснувшись их тени, благочестивый человек мог лишиться всей своей религиозности.',NULL),('cb.antya.5.524.ru','cb.antya.5.524','cb-ru','И всё же, по милости Нитьянанды, они тоже встали на путь чистого сознания Кришны.',NULL),('cb.antya.5.525.ru','cb.antya.5.525','cb-ru','Господь Чайтанья лично освободил множество живых существ, но с помощью Нитьянанды, Он освободил все три мира.',NULL),('cb.antya.5.526.ru','cb.antya.5.526','cb-ru','Тем или иным способом, но Нитьянанда освободил воров, жуликов, падших и презренных.',NULL),('cb.antya.5.527.ru','cb.antya.5.527','cb-ru','Теперь послушайте, как Нитьянанда Прабху освободил бандитов.',NULL),('cb.antya.5.528.ru','cb.antya.5.528','cb-ru','Жил в Навадвипе сын одного брахмана, равного которому не было ни среди жуликов, ни среди бандитов.',NULL),('cb.antya.5.529.ru','cb.antya.5.529','cb-ru','Он был главарём целой банды. Этот злокозненный человек только назывался брахманом.
Фраза наме се брахмана означает брахмана-бруве или мнимого брахмана. Качества и признаки такого брахмана-брувы описаны в Падма пуране и Ману-самхите (7.85).',NULL),('cb.antya.5.530.ru','cb.antya.5.530','cb-ru','Он безжалостно убивал людей и общался исключительно с подобными себе бандитами.',NULL),('cb.antya.5.531.ru','cb.antya.5.531','cb-ru','Однажды он увидел Нитьянанду Сварупу, украшенного божественными ожерельями, изделиями из золота, кораллов, драгоценных камней и жемчуга.',NULL),('cb.antya.5.532.ru','cb.antya.5.532','cb-ru','Увидев такое количество ценных украшений на теле Господа, бандит-брахман решил их украсть.',NULL),('cb.antya.5.533.ru','cb.antya.5.533','cb-ru','Куда бы ни пошёл Нитьянанда, брахман украдкой следовал за Ним, поджидая удобный момент для кражи Его украшений.',NULL),('cb.antya.5.534.ru','cb.antya.5.534','cb-ru','Нитьянанда как Сверхдуша, пребывающая в сердце каждого, знал о намерениях лукавого брахмана.',NULL),('cb.antya.5.535.ru','cb.antya.5.535','cb-ru','В Навадвипе жил один сведущий брахман по имени Хиранья Пандита, у которого не было никакого имущества.
Один из признаков сведущего брахмана, это отсутствие материальных ценностей.',NULL),('cb.antya.5.536.ru','cb.antya.5.536','cb-ru','Нитьянанда оставил Своих спутников, и с радостью поселился в доме этого счастливчика – Хираньи Пандита.',NULL),('cb.antya.5.537.ru','cb.antya.5.537','cb-ru','Злокозненный брахман был воплощением зла. Он привлёк других бандитов и придумал план ограбления.',NULL),('cb.antya.5.538.ru','cb.antya.5.538','cb-ru','"О братья, почему мы должны страдать? Богиня Чанди приготовила для нас сокровища, и все они находятся в одном месте".
"Только под покровительством Шри Чанди-маты мы можем исполнить наши материальные желания. Она милостиво предоставила нам сокровища, чтобы мы совершили ограбление".',NULL),('cb.antya.5.539.ru','cb.antya.5.539','cb-ru','"Все украшения на теле этого авадхуты сделаны из золота, жемчуга и бриллиантов".',NULL),('cb.antya.5.540.ru','cb.antya.5.540','cb-ru','"Я не могу сказать, сколько сотен тысяч рупий стоят Его украшения, но богиня Чанди собрала их в одном месте".',NULL),('cb.antya.5.541.ru','cb.antya.5.541','cb-ru','"Он живет один в доме Хираньи. Мы можем отправиться туда и забрать всё за какие-то полчаса".',NULL),('cb.antya.5.542.ru','cb.antya.5.542','cb-ru','"Приготовьте мечи и щиты, и этой ночью мы совершим набег на этот дом".',NULL),('cb.antya.5.543.ru','cb.antya.5.543','cb-ru','Решив действовать по плану, бандиты дождались ночи, прокрались к дому и устроили засаду.',NULL),('cb.antya.5.544.ru','cb.antya.5.544','cb-ru','Вооружённые мечами, ножами и трезубцами, они затаились рядом с домом, где жил Нитьянанда.',NULL),('cb.antya.5.545.ru','cb.antya.5.545','cb-ru','Ожидая в засаде, бандиты послали на разведку шпиона.',NULL),('cb.antya.5.546.ru','cb.antya.5.546','cb-ru','Нитьянанда Прабху принимал пищу, а преданные окружившие Его со всех сторон, пели имя Хари.',NULL),('cb.antya.5.547.ru','cb.antya.5.547','cb-ru','Преданные Нитьянанды были настолько опьянены экстазом сознания Кришны, что некоторые из них ревели как львы, а пение других было подобно звукам раскатов грома.',NULL),('cb.antya.5.548.ru','cb.antya.5.548','cb-ru','Некоторые плакали, поглощённые вкусами экстатической любви, в то время как другие громко смеялись и хлопали в ладоши.',NULL),('cb.antya.5.549.ru','cb.antya.5.549','cb-ru','Кто-то восклицал, "Хайа! Хайа!". В экстазе сознания Кришны, никто не спал.',NULL),('cb.antya.5.550.ru','cb.antya.5.550','cb-ru','Шпион вернулся и сказал бандитам, "Авадхута принимает пищу, а все остальные бодрствуют".',NULL),('cb.antya.5.551.ru','cb.antya.5.551','cb-ru','Бандиты решили, "Пусть поедят и лягут спать. Мы немного подождём, а затем совершим набег".
Слово хана означает "нападать с криками и возгласами".',NULL),('cb.antya.5.552.ru','cb.antya.5.552','cb-ru','Все бандиты засели под деревом в предвкушении того, что скоро станут обладателями чужого богатства.',NULL),('cb.antya.5.553.ru','cb.antya.5.553','cb-ru','Один из них сказал, "Я возьму Его золотые браслеты". Другой сказал, "А я хочу взять жемчужное ожерелье".',NULL),('cb.antya.5.554.ru','cb.antya.5.554','cb-ru','Кто-то сказал: "Я заберу Его серьги". Ещё один бандит добавил, "Я заберу Его золотое ожерелье".',NULL),('cb.antya.5.555.ru','cb.antya.5.555','cb-ru','Кто-то сказал, "Я возьму Его серебряные колокольчики". Так они сидя в засаде мечтали о грядущем богатстве.
Фраза мана-кала означает "объект наслаждения о котором мечтают".',NULL),('cb.antya.5.556.ru','cb.antya.5.556','cb-ru','В то же время, по воле Нитьянанды, богиня сна бросила свой взгляд на бандитов.',NULL),('cb.antya.5.557.ru','cb.antya.5.557','cb-ru','Все бандиты так и заснули в своей засаде. Они погрузились в такой глубокий сон, что не подавали признаков жизни.',NULL),('cb.antya.5.558.ru','cb.antya.5.558','cb-ru','Они были так сильно сбиты с толку энергией Господа, что не проснулись даже когда прошла ночь.',NULL),('cb.antya.5.559.ru','cb.antya.5.559','cb-ru','Проснулись бандиты от громкого карканья ворон. Они очень огорчились, обнаружив что настал рассвет.',NULL),('cb.antya.5.560.ru','cb.antya.5.560','cb-ru','Они быстро спрятали свои мечи и щиты в лесу и пошли принимать омовение в Ганге.',NULL),('cb.antya.5.561.ru','cb.antya.5.561','cb-ru','После этого бандиты обвиняя друг друга, стали расходиться по своим домам.',NULL),('cb.antya.5.562.ru','cb.antya.5.562','cb-ru','Один бандит сказал: "Ты заснул первым", а другой ответил: "Да, как только ты проснулся!"',NULL),('cb.antya.5.563.ru','cb.antya.5.563','cb-ru','Другой сказал, "К чему нам ссориться? Чанди спасла нас от ошибки".',NULL),('cb.antya.5.564.ru','cb.antya.5.564','cb-ru','Грешный брахман, гловарь бандитов, сказал: "Может хватит устраивать перебранки?"',NULL),('cb.antya.5.565.ru','cb.antya.5.565','cb-ru','"Что бы ни случилось, всё происходит по воле Чанди. Мы потеряли только один день, но будут другие".',NULL),('cb.antya.5.566.ru','cb.antya.5.566','cb-ru','"Я думаю, что Чанди смутила нас сном, потому что мы отправились на дело, не предложив ей своего поклонения".
Другой вариант слова аджи ("сегодня"), это аси ("пришёл").',NULL),('cb.antya.5.567.ru','cb.antya.5.567','cb-ru','"Нам следует устроить поклонение Чанди и предложить ей вино и мясо".
Вино и мясо – обязательные составляющие для поклонения богине Чанди.',NULL),('cb.antya.5.568.ru','cb.antya.5.568','cb-ru','Согласившись с этими доводами, все бандиты устроили поклонение Чанди и предложили ей мясо и вино.',NULL),('cb.antya.5.569.ru','cb.antya.5.569','cb-ru','На следующий день бандиты снова вооружились. Они были в одеждах из синей ткани и выглядели очень воинственно.',NULL),('cb.antya.5.570.ru','cb.antya.5.570','cb-ru','В глухую ночь, когда все уснули, бандиты окружили дом.',NULL),('cb.antya.5.571.ru','cb.antya.5.571','cb-ru','Подкравшись, они увидели много воинов, охраняющих дом.
Слово пайка означает "пехота", а слово ракхе означает "защищать".',NULL),('cb.antya.5.572.ru','cb.antya.5.572','cb-ru','Воины были вооружены, и окружали дом со всех сторон, постоянно повторяя имя Хари.',NULL),('cb.antya.5.573.ru','cb.antya.5.573','cb-ru','Они были высокими и сильными. Оснащённые всеми видами оружия, выглядели они очень угрожающе.',NULL),('cb.antya.5.574.ru','cb.antya.5.574','cb-ru','Разбойники прекрасно видели, что любой из этих воинов в одно мгновение может с лёгкостью убить сотню врагов.',NULL),('cb.antya.5.575.ru','cb.antya.5.575','cb-ru','Все они были украшены цветочными гирляндами, их тела были умащены сандаловой пастой и они беспрерывно воспевали святые имена.',NULL),('cb.antya.5.576.ru','cb.antya.5.576','cb-ru','Пока вооружённая охрана пела вокруг дома имена Кришны, Нитьянанда спал.',NULL),('cb.antya.5.577.ru','cb.antya.5.577','cb-ru','Увидев что происходит, разбойники удивились и пришли в замешательство. Они оставили дом и собрались в безлюдном месте.',NULL),('cb.antya.5.578.ru','cb.antya.5.578','cb-ru','Там бандиты начали делиться соображениями, "Откуда взялись все эти воины?"',NULL),('cb.antya.5.579.ru','cb.antya.5.579','cb-ru','Один бандит сказал: "Авадхута каким-то образом узнал о наших планах и где-то нанял этих военных для охраны".',NULL),('cb.antya.5.580.ru','cb.antya.5.580','cb-ru','Другой сказал, "О братья, я слышал от многих людей, что этот Авадхута очень мудр".',NULL),('cb.antya.5.581.ru','cb.antya.5.581','cb-ru','"Этот Авадхута Махашая настолько умён, что нанял собственную охрану".',NULL),('cb.antya.5.582.ru','cb.antya.5.582','cb-ru','"С другой стороны, воины которых мы видели, не похожи на обычных людей".',NULL),('cb.antya.5.583.ru','cb.antya.5.583','cb-ru','"Я думаю, что люди называют Его Госани, потому что Он обладает огромным могуществом".',NULL),('cb.antya.5.584.ru','cb.antya.5.584','cb-ru','Кто-то сказал: "О брат, ты просто глупец! Как может тот кто ест и одевается как Он, назвыаться Госани?"
Как того кто пирует и украшает себя тканью и украшениями, можно назвать хозяином своих чувств?',NULL),('cb.antya.5.585.ru','cb.antya.5.585','cb-ru','Брахман, главарь бандитов сказал, "Я знаю причину".',NULL),('cb.antya.5.586.ru','cb.antya.5.586','cb-ru','"Много влиятельных людей пришли отовсюду, чтобы увидеть этого Авадхуту".',NULL),('cb.antya.5.587.ru','cb.antya.5.587','cb-ru','"Это военачальник царя, который появился из ниоткуда, привёл с собой множество воинов".',NULL),('cb.antya.5.588.ru','cb.antya.5.588','cb-ru','"Эти солдаты сентиментальны, и потому поют имя Хари".
Слово бхавака, правильно пишется как бхавука, что означает "сентиментальный".',NULL),('cb.antya.5.589.ru','cb.antya.5.589','cb-ru','"Сейчас неподходящее время. Мы должны набраться терпения и переждать несколько дней, пока эти воины не уйдут".',NULL),('cb.antya.5.590.ru','cb.antya.5.590','cb-ru','"Поэтому, давайте сегодня разойдёмся по домам и спокойно подождём дней десять".',NULL),('cb.antya.5.591.ru','cb.antya.5.591','cb-ru','После слов, произнесённых главарём, разбойники отправились по домам. Между тем, Авадхута-чандра Прабху продолжал наслаждаться Своими играми.',NULL),('cb.antya.5.592.ru','cb.antya.5.592','cb-ru','Даже памятуя о тех, кто поклоняются лотосным стопам Нитьянанды, человек устраняет все препятствия на своём духовном пути.',NULL),('cb.antya.5.593.ru','cb.antya.5.593','cb-ru','Поэтому, когда Сам Нитьянанда наслаждается Своими играми, кто может создать Ему помехи?
Завистники всегда стараются создать помехи в начинаниях святых людей. Под влиянием своих греховных мыслей, они создают в этом мире препятствия любой полезной деятельности. Но никогда ни один завистник не сможет как-то помешать Нитьянанде, и Его желанию служить Господу Кришне.',NULL),('cb.antya.5.594.ru','cb.antya.5.594','cb-ru','Кто может воздвигнуть препятствия Господу, если любое невежество уничтожается памятованием о любом из Его преданных?
Никто не может создать препятствия для Шри Нитьянанды, который является хозяином всех слуг Верховного Господа. Если человек размышляет даже о слугах Шри Нитьянанды, всё невежество в форме отвращения к Верховному Господу, и все его греховные мысли исчезнут как дым.
Стих 595-596
Ганеша – разрушитель всех препятствий, и его спутники заняты служением Нитьянанде. Рудра – Его экспансия, уничтожает Вселенную. Когда Его экспансия Ананта приходит в беспокойство, то содрогаются все вселенные. Так как может Нитьянанда испытывать какой-либо страх?
Когда гуна-аватара – Рудра, который является частью полной части Нитьянанды, способен уничтожить вселенную; когда Ганапати и его спутники постоянно заняты служением Ему; когда Его экспансия – Шри Ананта, который поддерживает вселенную, слегка волнуется, то содрогаются четырнадцать миров – как может Нитьянанда испугаться когото? В Шримад-Бхагаватам (10.85.31) сказано:
"Ты — Верховный Господь, Душа всего сущего. Всего лишь частичное воплоще- ние Твоей полной экспансии творит, поддерживает и уничтожает мироздание. Сегодня я предаюсь Тебе". В Шримад-Бхагаватам (3.25.42) говорится:
"В страхе передо Мной, владыкой всего сущего дует ветер, в страхе передо Мной светит солнце, и повелитель туч Индра в страхе передо Мной посылает на землю дожди. Страшась Меня пылает огонь и смерть бродит по свету, собирая свою жатву, только потому что боится Меня". В Шримад-Бхагаватам (3.29.38-45) сказано:
"Господь Вишну, Верховная Личность Бога, который наслаждается всеми жертвоприношениями, является фактором времени и владыкой всех владык. Он входит в сердце всех живых существ, поддерживает жизнь каждого и является причиной того, что одно живое существо уничтожает другое".
"Господь, Верховная Личность Бога, ни к кому не питает пристрастия, у Него нет ни врагов, ни друзей. Он из сердца направляет тех кто помнит о Нём, и приводит к гибели тех, кто о Нём забыл".
"В страхе перед Верховным Господом дует ветер, в страхе перед Ним встаёт солнце, в страхе перед Ним идут дожди и в страхе перед Ним мириады небесных тел излучают свой свет".
"В страхе перед Верховной Личностью Бога деревья, лианы, травы и другие растения в свой срок покрываются цветами и плодоносят".
"Из страха перед Верховным Господом текут реки и океан не выходит из своих берегов. Только из страха перед Ним горит огонь и Земля с её горными кряжами не погружается в пучины океана вселенной".
"По воле Верховной Личности Бога небо позволяет космическому пространству вмещать многочисленные планеты, населённые мириадами живых существ. Все тело вселенной, покрытое семью оболочками, подчинено воле Всевышнего".
"В страхе перед Верховной Личностью Бога полубоги, управляющие гунами материальной природы, создают, сохраняют и разрушают вселенную; все живое и неживое в материальном мире подчинено их власти".
"У вечного времени нет ни начала, ни конца. Оно является представителем Верховного Господа, творца этого мира, предназначенного для существования порочных существ. Время служит причиной гибели проявленного мира, оно выполняет созидательные функции, заставляя одно живое существо появляться на свет из чрева другого, и разрушает вселенную, уничтожая даже повелителя смерти, Ямараджу". В Брахма-самхите (5.50) сказано:
"Я поклоняюсь изначальному Господу, Говинде. Ганеша всегда держит Его лотосные стопы на выпуклостях своей слоновьей головы. Эти стопы дают ему власть уничтожать все препятствия на пути процветания трёх миров".',NULL),('cb.antya.5.597.ru','cb.antya.5.597','cb-ru','Он свободно проводил киртаны по всей Навадвипе, и по Своей воле наслаждался играми с едой и сном.',NULL),('cb.antya.5.598.ru','cb.antya.5.598','cb-ru','С драгоценностями, украшавшими всё Его тело, Он выглядел в точности, как Баладева, сын Рохини.
ТЕКСТ 599
Он жевал орехи бетеля с камфорой и Его милая улыбка очаровывала людей всего мира.',NULL),('cb.antya.5.600.ru','cb.antya.5.600','cb-ru','Он бесстрашно и радостно бродил повсюду в сопровождении преданных.',NULL);